import React from "react";
import Marquee from "react-fast-marquee";
import img1 from "./images/01.png";
import img2 from "./images/02.png";
import img3 from "./images/03.png";
import "./App.css"; // Import the CSS file with styles for the marquee

function MarqueeExample() {
  function handleClick(imageIndex) {
    // Redirect to a different page depending on the clicked image
    switch (imageIndex) {
      case 0:
        window.location.href = "page1.html";
        break;
      case 1:
        window.location.href = "page2.html";
        break;
      case 2:
        window.location.href = "page3.html";
        break;
      default:
        break;
    }
  }

  function handleMouseEnter(e) {
    // Create and show the tooltip on mouse enter
    const tooltip = document.createElement("div");
    tooltip.className = "tooltip";
    tooltip.innerHTML = `
      <span class="tooltip-text">Click to learn more</span>
      <img class="tooltip-arrow" src="./images/arrow.png" alt="Tooltip arrow" />
    `;
    document.body.appendChild(tooltip);

    // Position the tooltip next to the mouse cursor
    const tooltipWidth = tooltip.offsetWidth;
    const tooltipHeight = tooltip.offsetHeight;
    const bodyRect = document.body.getBoundingClientRect();
    const mouseX = e.clientX - bodyRect.left;
    const mouseY = e.clientY - bodyRect.top;
    tooltip.style.left = mouseX + 20 + "px";
    tooltip.style.top = mouseY - tooltipHeight / 2 + "px";
  }

  function handleMouseLeave() {
    // Remove the tooltip on mouse leave
    const tooltip = document.querySelector(".tooltip");
    if (tooltip) {
      tooltip.remove();
    }
  }

  return (
    <div className="marquee-container">
      <Marquee gradient={false} speed={40} direction="up">
        <div
          className="marquee-item"
          onClick={() => handleClick(0)}
          onMouseEnter={handleMouseEnter}
          onMouseLeave={handleMouseLeave}
        >
          <div className="marquee-item-box">
            <img src={img1} alt="example" />
            <span>
              Lorem ipsum dolor sit amet, consectetur adipiscing elit.
            </span>
          </div>
        </div>
        <div
          className="marquee-item"
          onClick={() => handleClick(1)}
          onMouseEnter={handleMouseEnter}
          onMouseLeave={handleMouseLeave}
        >
          <div className="marquee-item-box">
            <img src={img2} alt="example" />
            <span>
              Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.
            </span>
          </div>
        </div>
        <div
          className="marquee-item"
          onClick={() => handleClick(2)}
          onMouseEnter={handleMouseEnter}
          onMouseLeave={handleMouseLeave}
        >
          <div className="marquee-item-box">
            <img src={img3} alt="example" />
            <span>
              Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris nisi.
            </span>
          </div>
        </div>
      </Marquee>
    </div>
  );
}

export default MarqueeExample;
